// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---
// The cursor is an opaque base64-encoded JSON payload of the sort keys
// of the last row on the current page: { created_at, id }.

function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64');
}

function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        parsed = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    // Validate the decoded shape so we never inject bad values into the query.
    if (
        parsed === null ||
        typeof parsed !== 'object' ||
        typeof parsed.id === 'undefined' ||
        typeof parsed.created_at === 'undefined'
    ) {
        throw new Error('Malformed cursor');
    }

    const createdAt = new Date(parsed.created_at);
    if (isNaN(createdAt.getTime())) {
        throw new Error('Malformed cursor');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ---
async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > 100) limit = 100;

    const after = req.query.after;

    let cursor = null;
    if (after) {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }
    }

    // LIMIT N+1: fetch one extra row to detect whether more pages exist.
    const fetchLimit = limit + 1;

    let result;
    if (cursor) {
        // Compound cursor for ORDER BY created_at DESC, id DESC.
        // "Next" rows are those strictly "less than" the cursor in that ordering.
        // Row comparison maps cleanly to the compound key:
        //   (created_at, id) < (cursorCreatedAt, cursorId)
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, fetchLimit]
        );
    } else {
        // No cursor → first page, no WHERE filter on the cursor keys.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [fetchLimit]
        );
    }

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore ? encodeCursor(posts[posts.length - 1]) : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation note: the compound comparison

The single most important detail is the WHERE clause. Because the sort is `created_at DESC, id DESC`, the "next page" consists of rows that come *after* the cursor in that descending order — i.e. rows whose `(created_at, id)` tuple is **less than** the cursor's tuple:

```sql
WHERE (created_at, id) < ($1, $2)
```

PostgreSQL's **row constructor comparison** evaluates this lexicographically exactly the way you want: a row qualifies if `created_at < cursor.created_at`, OR `created_at = cursor.created_at AND id < cursor.id`. This correctly handles ties on `created_at` and avoids both skipping and duplicating rows at page boundaries.

> Avoid the naive `created_at <= $1 AND id < $2` — that's a logically different (and wrong) condition. Use the tuple form, or expand it fully as `created_at < $1 OR (created_at = $1 AND id < $2)`.

For performance, back this with a matching composite index:
```sql
CREATE INDEX idx_posts_published_created_id
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

## Why cursor-based pagination is superior here

1. **Constant-time deep pagination.** `OFFSET N` forces PostgreSQL to read and discard N rows on every request, so page 5,000 gets progressively slower (O(offset)). A cursor with an indexed `(created_at, id) < (...)` seek jumps straight to the right spot — roughly O(log n) regardless of how deep you are.

2. **Stable results under writes.** With offset pagination, inserting or deleting a row while a user paginates shifts every subsequent row, causing **skipped or duplicated items** across pages. The cursor anchors to actual row values, so concurrent inserts/deletes don't corrupt the sequence.

3. **No expensive COUNT.** `SELECT COUNT(*)` on a large table is a full scan (or index-only scan) that grows with table size and is rarely worth it. Dropping it removes a real cost on every request; `hasMore` from the N+1 trick gives the only signal a feed/infinite-scroll UI actually needs.

4. **Opaque, encapsulated cursors.** Base64-encoding the JSON keeps the sort keys an implementation detail. You can later change what's inside the cursor (add a tiebreaker, switch sort field) without changing the public API contract.

The trade-off: you lose random access to an arbitrary page number (no "jump to page 50"). For a chronological feed like `posts ORDER BY created_at DESC`, that's exactly the right trade — feeds are consumed sequentially, not by page number.

