// ─── Cursor helpers ───────────────────────────────────────────────────────────

/**
 * Encode a (created_at, id) pair into an opaque base64 cursor string.
 * @param {Date|string} createdAt
 * @param {number|string} id
 * @returns {string}
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: new Date(createdAt).toISOString(), // normalise to ISO string
        id: String(id),
    });
    return Buffer.from(payload, 'utf8').toString('base64url'); // URL-safe base64
}

/**
 * Decode a cursor string back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or missing required fields.
 * @param {string} cursor
 * @returns {{ created_at: string, id: string } | null}
 */
function decodeCursor(cursor) {
    if (!cursor) return null;

    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        // Validate the shape — both fields must be present and non-empty
        if (
            typeof parsed.created_at !== 'string' ||
            !parsed.created_at ||
            parsed.id === undefined ||
            parsed.id === null ||
            parsed.id === ''
        ) {
            return null;
        }

        // Ensure created_at is actually a valid date string before hitting the DB
        if (isNaN(Date.parse(parsed.created_at))) {
            return null;
        }

        return { created_at: parsed.created_at, id: String(parsed.id) };
    } catch {
        // JSON.parse threw — cursor was garbage
        return null;
    }
}

// ─── Route handler ────────────────────────────────────────────────────────────

const MAX_LIMIT = 100; // guard against runaway page sizes

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ──────────────────────────────────────────
    const limit = Math.min(parseInt(req.query.limit) || 20, MAX_LIMIT);

    let cursor = null;
    if (req.query.after) {
        cursor = decodeCursor(req.query.after);
        if (!cursor) {
            // Cursor was provided but is unreadable — fail loudly so clients
            // don't silently re-request the wrong page.
            return res.status(400).json({
                error: 'Invalid cursor. The `after` parameter is malformed or expired.',
            });
        }
    }

    // ── 2. Build and run the query ───────────────────────────────────────────
    //
    // Sorting: created_at DESC, id DESC
    // "After the cursor" in this order means strictly smaller in the
    // (created_at, id) tuple:
    //
    //   (created_at < $cursor_ts)
    //   OR
    //   (created_at = $cursor_ts AND id < $cursor_id)
    //
    // We fetch limit+1 rows so we can detect whether a next page exists
    // without running a separate COUNT query.
    let result;

    if (cursor) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                      created_at < $1
                      OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── 3. Apply LIMIT+1 trick ───────────────────────────────────────────────
    const rows = result.rows;
    const hasMore = rows.length > limit;

    // Trim the sentinel row before returning to the client
    const posts = hasMore ? rows.slice(0, limit) : rows;

    // ── 4. Build the next cursor from the LAST row we're returning ───────────
    //      (not the sentinel row — that stays hidden)
    const lastPost = posts[posts.length - 1];
    const nextCursor =
        hasMore && lastPost
            ? encodeCursor(lastPost.created_at, lastPost.id)
            : null;

    // ── 5. Respond ───────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor, // null when this is the last page
            limit,
        },
    });
}
```

